b1 = -a0_inv*(1 + c)
b2 = a0_inv*(1 + c)/2

static z1 = 0
static z2 = 0

y = b0*IN[0] + z1
z1 = b1*IN[0] - a1*y + z2
z2 = b2*IN[0] - a2*y

